import{_ as a,o as i,c as o,a2 as r}from"./chunks/framework.DCVnL8g5.js";const m=JSON.parse('{"title":"Optimizacion y administracion de NiFi","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/nifi/03-optimizacion-y-administracion.md","filePath":"data-engineering/nifi/03-optimizacion-y-administracion.md","lastUpdated":1782521464000}'),s={name:"data-engineering/nifi/03-optimizacion-y-administracion.md"};function n(t,e,l,d,c,u){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="optimizacion-y-administracion-de-nifi" tabindex="-1">Optimizacion y administracion de NiFi <a class="header-anchor" href="#optimizacion-y-administracion-de-nifi" aria-label="Permalink to &quot;Optimizacion y administracion de NiFi&quot;">​</a></h1><p>Optimizar NiFi significa equilibrar rendimiento, estabilidad y operabilidad. No se trata solo de subir concurrencia: tambien hay que controlar colas, repositorios, back pressure, tiempos de ejecucion y dependencias externas.</p><h2 id="donde-se-consume-rendimiento" tabindex="-1">Donde se consume rendimiento <a class="header-anchor" href="#donde-se-consume-rendimiento" aria-label="Permalink to &quot;Donde se consume rendimiento&quot;">​</a></h2><p>Los cuellos de botella suelen aparecer en:</p><ul><li>Procesadores que esperan red o APIs externas.</li><li>Escrituras lentas a disco, base de datos o Kafka.</li><li>Transformaciones pesadas sobre contenido grande.</li><li>Colas sin back pressure.</li><li>Reintentos excesivos.</li><li>Repositorios mal dimensionados.</li><li>Cluster con nodos desequilibrados.</li></ul><p>Mide antes de cambiar parametros globales.</p><h2 id="concurrent-tasks" tabindex="-1">Concurrent tasks <a class="header-anchor" href="#concurrent-tasks" aria-label="Permalink to &quot;Concurrent tasks&quot;">​</a></h2><p>Cada processor puede ejecutar varias tareas concurrentes. Aumentarlas puede mejorar throughput si el processor esta limitado por I/O, pero puede empeorar el sistema si el destino no soporta mas carga.</p><p>Buenas practicas:</p><ul><li>Sube concurrencia gradualmente.</li><li>Observa CPU, memoria, disco y latencia del destino.</li><li>No aumentes todo a la vez.</li><li>Ajusta primero los processors que realmente bloquean el flujo.</li></ul><h2 id="run-schedule" tabindex="-1">Run schedule <a class="header-anchor" href="#run-schedule" aria-label="Permalink to &quot;Run schedule&quot;">​</a></h2><p>El run schedule controla cada cuanto se dispara un processor.</p><p>Ejemplos:</p><ul><li><code>0 sec</code>: intenta ejecutar continuamente.</li><li><code>5 sec</code>: ejecuta cada cinco segundos.</li><li><code>1 min</code>: util para polling menos agresivo.</li></ul><p>Un processor que consulta una API externa no deberia ejecutarse sin pausa si la API tiene limites.</p><h2 id="back-pressure" tabindex="-1">Back pressure <a class="header-anchor" href="#back-pressure" aria-label="Permalink to &quot;Back pressure&quot;">​</a></h2><p>Back pressure evita que un flujo produzca mas datos de los que la siguiente fase puede consumir.</p><p>Se configura en las connections:</p><ul><li>Por numero de FlowFiles.</li><li>Por tamano total en cola.</li></ul><p>Sin back pressure, un destino lento puede llenar repositorios y afectar a todo el cluster.</p><h2 id="repositorios" tabindex="-1">Repositorios <a class="header-anchor" href="#repositorios" aria-label="Permalink to &quot;Repositorios&quot;">​</a></h2><p>NiFi usa varios repositorios internos:</p><ul><li><strong>FlowFile Repository:</strong> estado de FlowFiles.</li><li><strong>Content Repository:</strong> contenido real.</li><li><strong>Provenance Repository:</strong> historial de eventos.</li><li><strong>Database Repository:</strong> estado interno en versiones modernas.</li></ul><p>Recomendaciones:</p><ul><li>Usar discos rapidos para repositorios criticos.</li><li>Separar content y provenance si el volumen es alto.</li><li>Configurar retencion de provenance segun necesidades reales.</li><li>Monitorizar uso de disco.</li></ul><h2 id="cluster" tabindex="-1">Cluster <a class="header-anchor" href="#cluster" aria-label="Permalink to &quot;Cluster&quot;">​</a></h2><p>En cluster, varios nodos ejecutan el mismo flujo.</p><p>Ten en cuenta:</p><ul><li>Algunos processors deben ejecutarse solo en el primary node.</li><li>Las colas pertenecen a nodos concretos.</li><li>El balanceo de carga entre nodos puede ayudar en flujos distribuidos.</li><li>Un nodo lento puede acumular cola aunque otros esten sanos.</li></ul><h2 id="seguridad" tabindex="-1">Seguridad <a class="header-anchor" href="#seguridad" aria-label="Permalink to &quot;Seguridad&quot;">​</a></h2><p>En produccion, NiFi debe operar con seguridad activada.</p><p>Aspectos basicos:</p><ul><li>HTTPS.</li><li>Autenticacion.</li><li>Autorizacion por politicas.</li><li>Certificados correctamente gestionados.</li><li>Credenciales como parametros sensibles.</li><li>Acceso minimo necesario.</li><li>Auditoria de cambios.</li></ul><h2 id="mantenimiento" tabindex="-1">Mantenimiento <a class="header-anchor" href="#mantenimiento" aria-label="Permalink to &quot;Mantenimiento&quot;">​</a></h2><p>Tareas habituales:</p><ul><li>Revisar colas acumuladas.</li><li>Limpiar datos obsoletos.</li><li>Revisar provenance y retencion.</li><li>Actualizar processors y extensiones.</li><li>Versionar cambios en Registry.</li><li>Validar backups de configuracion.</li><li>Revisar logs y uso de disco.</li></ul><h2 id="problemas-frecuentes" tabindex="-1">Problemas frecuentes <a class="header-anchor" href="#problemas-frecuentes" aria-label="Permalink to &quot;Problemas frecuentes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Sintoma</th><th>Posible causa</th><th>Accion</th></tr></thead><tbody><tr><td>Cola crece sin parar</td><td>Destino lento</td><td>Revisar back pressure y throughput</td></tr><tr><td>CPU alta</td><td>Transformacion costosa</td><td>Reducir concurrencia o mover a Spark</td></tr><tr><td>Disco lleno</td><td>Content/provenance acumulado</td><td>Ajustar retencion y revisar colas</td></tr><tr><td>Muchos retries</td><td>Dependencia externa inestable</td><td>Separar retry y failure</td></tr><tr><td>Cluster desequilibrado</td><td>Flujo no balanceado</td><td>Revisar load balancing</td></tr></tbody></table><h2 id="checklist-de-produccion" tabindex="-1">Checklist de produccion <a class="header-anchor" href="#checklist-de-produccion" aria-label="Permalink to &quot;Checklist de produccion&quot;">​</a></h2><ul><li>Seguridad activada.</li><li>Repositorios dimensionados.</li><li>Back pressure configurado.</li><li>Retencion de provenance definida.</li><li>Flujos versionados.</li><li>Parametros separados por entorno.</li><li>Alertas de disco, colas y errores.</li><li>Runbook de parada, arranque y recuperacion.</li></ul><h2 id="recursos-relacionados" tabindex="-1">Recursos relacionados <a class="header-anchor" href="#recursos-relacionados" aria-label="Permalink to &quot;Recursos relacionados&quot;">​</a></h2><ul><li><a href="./05-colas-back-pressure-y-errores">Colas, back pressure y errores</a></li><li><a href="./06-registry-despliegue-y-observabilidad">Registry, despliegue y observabilidad</a></li><li><a href="./../pipelines/01-introduccion">Pipelines de datos</a></li></ul>',42)])])}const h=a(s,[["render",n]]);export{m as __pageData,h as default};
